import json, re

lines = open('ios_crash.ips').readlines()
raw = ''.join(lines[1:])
raw = re.sub(r'\"vmregioninfo\"', '\"vmregioninfo_lower\"', raw)
crash = json.loads(raw)

# Check for any extra fields
skip = {'threads','usedImages','legacyInfo','sharedCache'}
for k in crash:
    if k not in skip:
        v = crash[k]
        if isinstance(v, (str,int,float,bool)):
            print(f'{k}: {v}')
        elif isinstance(v, dict):
            print(f'{k}: {json.dumps(v, indent=2)[:500]}')
        elif isinstance(v, list) and len(v) < 20:
            print(f'{k}: {json.dumps(v)[:500]}')
        else:
            print(f'{k}: ({type(v).__name__}, len={len(v)})')
" 2>&1

